create table public.collection_actions(id uuid primary key default gen_random_uuid(),organization_id uuid not null references organizations,account_id uuid not null references credit_accounts,action_type text not null check(action_type in('call','whatsapp','promise_to_pay','visit','payment_arrangement','unreachable')),notes text not null,promised_date date,actor_id uuid not null references profiles,created_at timestamptz not null default now());
alter table public.collection_actions enable row level security;alter table public.collection_actions force row level security;
create policy collection_actions_read on public.collection_actions for select to authenticated using(organization_id=private.current_organization_id() and (private.has_role('collections_agent') or private.has_role('credit_manager') or private.has_role('organization_admin') or private.has_role('organization_owner')));
create or replace function public.record_collection_action(p_account_id uuid,p_action_type text,p_notes text,p_promised_date date default null)returns uuid language plpgsql security definer set search_path='' as $$
declare v_account public.credit_accounts%rowtype;v_id uuid;begin select * into v_account from public.credit_accounts where id=p_account_id and organization_id=private.current_organization_id();if not found or not(private.has_role('collections_agent') or private.has_role('credit_manager') or private.has_role('organization_owner') or private.has_role('organization_admin'))then raise exception 'No autorizado' using errcode='42501';end if;if p_action_type not in('call','whatsapp','promise_to_pay','visit','payment_arrangement','unreachable')or nullif(trim(p_notes),'')is null then raise exception 'Gestión inválida';end if;if p_action_type in('promise_to_pay','payment_arrangement')and p_promised_date is null then raise exception 'Indique la fecha prometida';end if;insert into public.collection_actions(organization_id,account_id,action_type,notes,promised_date,actor_id)values(v_account.organization_id,v_account.id,p_action_type,trim(p_notes),p_promised_date,auth.uid())returning id into v_id;return v_id;end $$;
revoke all on function public.record_collection_action(uuid,text,text,date)from public,anon;grant execute on function public.record_collection_action(uuid,text,text,date)to authenticated;
